import React from 'react';
import {StyleSheet, View} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withDecay} from 'react-native-reanimated';
export function TrackpadCanvas({children}: {children: React.ReactNode}) {
  const tx = useSharedValue(0); const ty = useSharedValue(0); const sTx = useSharedValue(0); const sTy = useSharedValue(0);
  const pan = Gesture.Pan().minPointers(2).maxPointers(2).onStart(() => { sTx.value = tx.value; sTy.value = ty.value; }).onUpdate(e => { tx.value = sTx.value + e.translationX; ty.value = sTy.value + e.translationY; }).onEnd(e => { tx.value = withDecay({velocity: e.velocityX}); ty.value = withDecay({velocity: e.velocityY}); });
  const style = useAnimatedStyle(() => ({transform: [{translateX: tx.value}, {translateY: ty.value}]}));
  return (<GestureDetector gesture={pan}><Animated.View style={[{flex:1}, style]}>{children}</Animated.View></GestureDetector>);
}

import React, {useMemo} from 'react';
import {StyleSheet, View, Text, Pressable, Dimensions} from 'react-native';
import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {interpolate, useAnimatedStyle, useSharedValue, withSpring} from 'react-native-reanimated';
const SCREEN_H = Dimensions.get('window').height;
export function ModalStackWithDismissableCardsAppleWallet({open, onClose, children}: {open: boolean; onClose: () => void; children: React.ReactNode}) {
  const snaps = useMemo(() => [SCREEN_H * 0.74, SCREEN_H * 0.38, SCREEN_H * 0.1], []);
  const y = useSharedValue(open ? snaps[1] : SCREEN_H);
  const pan = Gesture.Pan().onUpdate((e) => { y.value = Math.max(snaps[2], snaps[1] + e.translationY); }).onEnd((e) => { const projected = y.value + e.velocityY * 0.16; const next = snaps.reduce((best, snap) => Math.abs(projected - snap) < Math.abs(projected - best) ? snap : best, snaps[0]); y.value = withSpring(next, {damping: 22, stiffness: 220}); });
  const sheetStyle = useAnimatedStyle(() => ({transform: [{translateY: y.value}]}));
  const backdropStyle = useAnimatedStyle(() => ({opacity: interpolate(y.value, [snaps[0], snaps[2]], [0.08, 0.46])}));
  return <View pointerEvents={open ? 'auto' : 'none'} style={StyleSheet.absoluteFill}><Animated.View style={[styles.backdrop, backdropStyle]} /><GestureDetector gesture={pan}><Animated.View style={[styles.sheet, sheetStyle]} accessibilityViewIsModal accessibilityLabel="Modal stack with dismissable cards (Apple Wallet style)"><View style={styles.handle} /><Text style={styles.title}>Modal stack with dismissable cards (Apple Wallet style)</Text>{children}<Pressable onPress={onClose} accessibilityRole="button" style={styles.close}><Text>Close</Text></Pressable></Animated.View></GestureDetector></View>;
}
