import React from 'react';
import {StyleSheet, View} from 'react-native';
import Animated, {useSharedValue, useAnimatedStyle, withTiming} from 'react-native-reanimated';
export function SkeletonCrossfade({loading, skeleton, children}: {loading: boolean; skeleton: React.ReactNode; children: React.ReactNode}) {
  const op = useSharedValue(loading ? 0 : 1);
  React.useEffect(() => { op.value = withTiming(loading ? 0 : 1, {duration: 280}); }, [loading]);
  const skelStyle = useAnimatedStyle(() => ({opacity: 1 - op.value}));
  const contentStyle = useAnimatedStyle(() => ({opacity: op.value}));
  return (<View>{loading && <Animated.View style={[StyleSheet.absoluteFill, skelStyle]}>{skeleton}</Animated.View>}<Animated.View style={contentStyle} pointerEvents={loading ? 'none' : 'auto'}>{children}</Animated.View></View>);
}

