import React, {useEffect} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, withTiming, useDerivedValue} from 'react-native-reanimated';
export function RadialProgress({value, max = 100, size = 120, stroke = 12, color = '#0A84FF'}: {value: number; max?: number; size?: number; stroke?: number; color?: string}) {
  const p = useSharedValue(0);
  useEffect(() => { p.value = withTiming(value/max, {duration: 700}); }, [value]);
  const r = size/2 - stroke/2;
  const path = useDerivedValue(() => { const path = Skia.Path.Make(); path.addArc({x: stroke/2, y: stroke/2, width: r*2, height: r*2}, -90, p.value * 360); return path; });
  return (<View style={{width: size, height: size, alignItems:'center', justifyContent:'center'}}><Canvas style={StyleSheet.absoluteFill}><Path path={Skia.Path.Make().addCircle(size/2, size/2, r)} style='stroke' strokeWidth={stroke} color='#2C2C2E'/><Path path={path} style='stroke' strokeWidth={stroke} strokeCap='round' color={color}/></Canvas><Text style={{color:'#fff', fontSize:20, fontWeight:'600', fontVariant:['tabular-nums']}}>{Math.round((value/max)*100)}%</Text></View>);
}

